#include <omp.h>

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

static void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
    int i, j;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];
    int array_offset;

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i][j] = m[array_offset + j];
        }
        array_offset += matrix_dim;
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        int row, col;

        for (row = i + 1; row < BLOCK_SIZE; row++) {
            for (j = 0; j < i; j++) {
                shadow[row][i] -= shadow[row][j] * shadow[j][i];
            }
            shadow[row][i] /= shadow[i][i];
        }

        row = i + 1;
        for (col = i + 1; col < BLOCK_SIZE; col++) {
            for (j = 0; j < i + 1; j++) {
                shadow[row][col] -= shadow[row][j] * shadow[j][col];
            }
        }
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[array_offset + j] = shadow[i][j];
        }
        array_offset += matrix_dim;
    }
}

static void lud_perimeter_block_omp(float *m, int matrix_dim, int offset, int block)
{
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];
    int i, j;
    int array_offset;
    int global_col_offset = (block + 1) * BLOCK_SIZE;

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            dia[i][j] = m[array_offset + j];
        }
        array_offset += matrix_dim;
    }

    array_offset = offset * matrix_dim + offset + global_col_offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            peri_row[i][j] = m[array_offset + j];
        }
        array_offset += matrix_dim;
    }

    array_offset = (offset + global_col_offset) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            peri_col[i][j] = m[array_offset + j];
        }
        array_offset += matrix_dim;
    }

    for (j = 0; j < BLOCK_SIZE; j++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            int k;
            for (k = 0; k < i; k++) {
                peri_row[i][j] -= dia[i][k] * peri_row[k][j];
            }
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        int col;
        for (col = 0; col < BLOCK_SIZE; col++) {
            int k;
            for (k = 0; k < col; k++) {
                peri_col[i][col] -= peri_col[i][k] * dia[k][col];
            }
            peri_col[i][col] /= dia[col][col];
        }
    }

    array_offset = (offset + 1) * matrix_dim + offset + global_col_offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[array_offset + j] = peri_row[i][j];
        }
        array_offset += matrix_dim;
    }

    array_offset = (offset + global_col_offset) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[array_offset + j] = peri_col[i][j];
        }
        array_offset += matrix_dim;
    }
}

static void lud_internal_block_omp(float *m, int matrix_dim, int offset, int block_x, int block_y)
{
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];
    int i, j, k;
    int global_row_id = offset + (block_y + 1) * BLOCK_SIZE;
    int global_col_id = offset + (block_x + 1) * BLOCK_SIZE;

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            peri_row[i][j] = m[(offset + i) * matrix_dim + global_col_id + j];
            peri_col[i][j] = m[(global_row_id + i) * matrix_dim + offset + j];
        }
    }

    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < BLOCK_SIZE; k++) {
                sum += peri_col[i][k] * peri_row[k][j];
            }
            m[(global_row_id + i) * matrix_dim + global_col_id + j] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim)
{
    int i = 0;

    if (omp_num_threads > 0) {
        omp_set_num_threads(omp_num_threads);
    }

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        int blocks;

        lud_diagonal_omp(m, matrix_dim, i);

        blocks = (matrix_dim - i) / BLOCK_SIZE - 1;

#pragma omp parallel for schedule(static)
        for (int b = 0; b < blocks; b++) {
            lud_perimeter_block_omp(m, matrix_dim, i, b);
        }

#pragma omp parallel for collapse(2) schedule(static)
        for (int by = 0; by < blocks; by++) {
            for (int bx = 0; bx < blocks; bx++) {
                lud_internal_block_omp(m, matrix_dim, i, bx, by);
            }
        }
    }

    lud_diagonal_omp(m, matrix_dim, i);
}
